bool cent_test_gemv_16x16_relu() {
    xil_printf("\r\n--- Running 16x16 GEMV with ReLU Activation Test ---\r\n");

    // Print the input matrix in hex {w11, w12, ..., w1n}, {w21, w22, ..., w2n}, ..., {wm1, wm2, ..., wmn} format
    xil_printf("matrix W:\r\n");
    print_mat(&W_16x16[0][0], 16, 16);

    // Print the input vector in hex {va1, va2, ..., va16} format
    xil_printf("Input vector x:\r\n");
    print_vec(x_16x1, 16);

    // Print the bias vector in hex {vb1, vb2, ..., vb16} format
    xil_printf("Bias vector b:\r\n");
    print_vec(bias_16x1, 16);

    xil_printf("Loading vector x and matrix W into shared buffer...\r\n");
    // Write vec_x to shared buffer index 0
    cent_write_shared_buffer(0, x_16x1);

    // Write mat_W to shared buffer index 1 to index 16 (one row per index)
    for (int r = 0; r < 16; r++) {
        cent_write_shared_buffer(1 + r, &W_16x16[r][0]);
    }

    // Write bias to shared buffer index 17
    cent_write_shared_buffer(17, bias_16x1);

    // Build a program to perform GEMV as follows:
    // 16x WR_SBK to write each row of mat_W from shared buffer to PIM banks (one row per bank)
    // 1x  WR_GB to write vec_x from shared buffer to global buffer
    // 1x  WR_BIAS to write bias to accumulation register 0 in PIM PU
    // 1x  MAC_ABK to perform the matrix-vector multiplication (GEMV) and write results to accumulation register 0 in PIM PU
    // 1x  AF to apply activation function ReLU to the results in accumulation register 0 in PIM PU and write results back to accumulation register 0
    // 1x  RD_MAC to read the results from accumulation registers in PIM PU to shared buffer
    cent_instr_t program_instructions[21];
    u32 program_length = 21; // 16 WR_SBK + 1 WR_GB + 1 WR_BIAS + 1 MAC_ABK + 1 AF + 1 RD_MAC
    u32 program_start_index = 0; // start at the beginning of the instruction buffer

    // Build the 16 WR_SBK instructions to write each row of mat_W from shared buffer to PIM banks at index 0 (one row per bank)
    for (int i = 0; i < 16; i++) {
        program_instructions[i] = build_wr_sbk(0, 1, i, 0, 0, 1 + i); // rows start from index 1 in shared buffer
    }

    // Build the WR_GB instruction to write vec_x from shared buffer to global buffer
    program_instructions[16] = build_wr_gb(0, 1, 0, 0); // vec_x is at index 0 in shared buffer

    // Build the WR_BIAS instruction to write bias to accumulation register 0 in PIM PU from shared buffer index 17
    program_instructions[17] = build_wr_bias(0, 17, 0); // bias is at index 17 in shared buffer

    // Build the MAC_ABK instruction to perform the matrix-vector multiplication (GEMV) and write results to accumulation register 0 in PIM PU
    program_instructions[18] = build_mac_abk(0, 1, 0, 0, 0, MAC_OP_GEMV, 0);

    // Build the AF instruction to apply activation function ReLU to the results in accumulation register 0 in PIM PU and write results back to accumulation register 0
    program_instructions[19] = build_af(0, AFID_RELU, 0);

    // Build the RD_MAC instruction to read the results from accumulation register 0 in PIM PU to shared buffer index 18
    program_instructions[20] = build_rd_mac(0, 18, 0); // read results to index 18 in shared buffer

    // Construct the program struct
    cent_program_t program = {
        .instructions = program_instructions,
        .length = program_length,
        .start_index = program_start_index
    };

    // Load the program into the instruction buffer
    xil_printf("Loading program into instruction buffer\r\n");
    cent_load_program(&program);

    // Write interface control registers
    xil_printf("Writing control registers to start execution\r\n");
    // Write 0x1 to ctrl register to enable
    cent_write_ctrl(0x1);
    // Write start index of the program to cmd_base register
    cent_write_cmd_base(program.start_index * sizeof(cent_instr_t));
    // Write length of the program to cmd_len register
    cent_write_cmd_len(program.length);
    // Fire the doorbell to start execution
    cent_fire_doorbell();

    // Poll the status register until no longer busy (busy is bit 1 in status register)
    xil_printf("Polling status register...\r\n");
    u32 status;
    do {
        status = cent_read_status();
    } while (status & 0x2);

    // Read performance register
    u32 perf = cent_read_perf();
    xil_printf("Performance in cycles: %u\r\n", perf);

    // Clear sticky bits
    cent_write_status(status);

    // Read the results from shared buffer index 18
    u16 result[16];
    cent_read_shared_buffer(18, result);

    // Print the results
    xil_printf("GEMV Result with ReLU Activation in bf16 hex format:\r\n");
    print_vec(result, 16);

    // Verify results
    bool passed = true;
    for (int i = 0; i < 16; i++) {
        // Calculate ULPS error by converting expected and actual results to signed 16-bit integers and taking the absolute difference
        // This assumes that both result and expected_result are both positive or both negative
        const s16 tol = 5; // Activation functions can introduce some error since they are implemented in a piecewise linear approximation in hardware.
        s16 err = abs((s16)result[i] - (s16)expected_result_16x1_gemv_relu[i]);
        xil_printf("result[%d] = 0x%04X, expected = 0x%04X, abs error = %u\r\n", i, result[i], expected_result_16x1_gemv_relu[i], err);
        if (err > tol) {
            passed = false;
        }
    }
    if (passed) {
        xil_printf("16x16 GEMV with ReLU Activation Test Passed!!\r\n");
    } else {
        xil_printf("16x16 GEMV with ReLU Activation Test Failed!! See output above.\r\n");
    }

    return passed;
}

bool cent_test_gemv_32x32() {
    xil_printf("\r\n--- Running 32x32 GEMV with No Activation Test V1 ---\r\n");

    // Print the input matrix in hex {w11, w12, ..., w1n}, {w21, w22, ..., w2n}, ..., {wm1, wm2, ..., wmn} format
    xil_printf("matrix W:\r\n");
    print_mat(&W_32x32[0][0], 32, 32);
    // Print the input vector in hex {va1, va2, ..., va32} format
    xil_printf("Input vector x:\r\n");
    print_vec(x_32x1, 32);
    // Print the bias vector in hex {vb1, vb2, ..., vb32} format
    xil_printf("Bias vector b:\r\n");
    print_vec(bias_32x1, 32);

    // NOTE 1:
    // The mental model is that 32x32 matrix will be divided into 4 16x16 sub-matrices and stored in RO=0,CO=0,1,2,3. Each 16x16 sub-matrix will be processed in the same way as the previous test.
    // TOP    LEFT  16x16 --> RO=0,CO=0
    // TOP    RIGHT 16x16 --> RO=0,CO=1
    // BOTTOM LEFT  16x16 --> RO=0,CO=2
    // BOTTOM RIGHT 16x16 --> RO=0,CO=3
    // The 32x1 input vector will be split into two 16x1 subvectors, and stored in global buffer as follows:
    // TOP    16x1 --> GB=0
    // BOTTOM 16x1 --> GB=1
    // From above, MAC_ABK instruction will be issued as follows:
    // 1) Issue MAC_ABK with RO=0,CO=0,GB=0 to process TOP    LEFT  with TOP    16x1 global buffer vector and accumulate in REGID=0
    // 3) Issue MAC_ABK with RO=0,CO=1,GB=1 to process TOP    RIGHT with BOTTOM 16x1 global buffer vector and accumulate in REGID=0
    // 2) Issue MAC_ABK with RO=0,CO=2,GB=0 to process BOTTOM LEFT  with TOP    16x1 global buffer vector and accumulate in REGID=1
    // 4) Issue MAC_ABK with RO=0,CO=3,GB=1 to process BOTTOM RIGHT with BOTTOM 16x1 global buffer vector and accumulate in REGID=1
    // Since Opsize increments CO and GB, we can reduce the first two MAC_ABK instructions into one instruction with OPsize=2, and the second two MAC_ABK instructions into one instruction with OPsize=2, for a total of 2 MAC_ABK instructions to process the entire 32x32 matrix-vector multiplication.

    // NOTE 2:
    // For the 16x4 WR_SBK instructions (16 WR_SBK for each sub-matrix) we can make use of OPsize to reduce the number of instructions needed from 64 to 16 using OPsize=4, i.e. each WR_SBK instruction will write 4 vectors- a row of each 16x16 sub-matrix - to a PIM bank in RO=0,CO=0,1,2,3. 
    // To make this possible matrix W should be stored in a specific format in shared buffer, that is, each row of the 16x16 sub-matrix should be stored in order in shared buffer, such that e.g. 
    // W[0][0-15]   in SBUF[0+s]
    // W[0][16-31]  in SBUF[1+s] 
    // W[16][0-15]  in SBUF[2+s]
    // W[16][16-31] in SBUF[3+s]
    // this is to match the way WR_SBK with OPsize=4 will read from shared buffer and write to PIM banks as described above.)
    // s is a generic offset in shared buffer, which in this case is 2, since the first two indices of shared buffer are used to store the input vector x as shown below.
    // Notice how the mapping above follows a "row-major" order in other words, we go through the horizontal sub-matrices first (TOP LEFT, TOP RIGHT) and then the bottom horizontal sub-matrices (BOTTOM LEFT, BOTTOM RIGHT) and so on.

    xil_printf("Loading vector x and matrix W into shared buffer...\r\n");
    // Write vec_x to shared buffer index 0 (TOP 16x1) and index 1 (BOTTOM 16x1)
    cent_write_shared_buffer(0, &x_32x1[0]); // write first 16 elements
    cent_write_shared_buffer(1, &x_32x1[16]); // write next 16 elements

    // Write W to shared buffer index 2 to index 65. 4 16x16 sub-matrices, each take 16 indices in shared buffer. 
    // This helps with the way WR_SBK with OPsize=2 will read from shared buffer and write to PIM banks as described above (NOTE 2).
    // for (int r = 0; r < 16; r++) { // For each row in the sub-matrices (16 rows total)
    //     // Each sub-matrix in a "row-major" order.
    //     cent_write_shared_buffer(2 + (4*r), &W_32x32[r][0]); // sub-matrix TOP LEFT 16x16
    //     cent_write_shared_buffer(2 + (4*r) + 1, &W_32x32[r][16]); // sub-matrix TOP RIGHT 16x16
    //     cent_write_shared_buffer(2 + (4*r) + 2, &W_32x32[r+16][0]); // sub-matrix BOTTOM LEFT 16x16
    //     cent_write_shared_buffer(2 + (4*r) + 3, &W_32x32[r+16][16]); // sub-matrix BOTTOM RIGHT 16x16
    // }

    // The above commented simple loop can be generalized to handle any size of matrix W. 
    // In a 32x32 matrix, we have: 2 horizontal tiles (TOP, BOTTOM) and 2 vertical tiles (LEFT, RIGHT). Each tile is a 16x16 sub-matrix.
    // The following nested loop will iterate through each tile and each row in the tile and write to shared buffer in a "row-major" order as described above.
    for (int r = 0; r < 16; r++) { // For each row in the sub-matrices (16 rows total)
        for (int h_tile = 0; h_tile < 2; h_tile++) { // For each horizontal tile (TOP, BOTTOM)
            for (int v_tile = 0; v_tile < 2; v_tile++) { // For each vertical tile (LEFT, RIGHT)
                int sbuf_idx = 2 + (4*r) + (2*h_tile) + v_tile;
                int w_row = r + (16*h_tile); // row in W
                int w_col = v_tile * 16; // column in W

                cent_write_shared_buffer(sbuf_idx, &W_32x32[w_row][w_col]);
            }
        }
    }

    // Write bias to shared buffer index 66 (first 16 elements) and index 67 (next 16 elements)
    cent_write_shared_buffer(66, &bias_32x1[0]);
    cent_write_shared_buffer(67, &bias_32x1[16]);

    // Build a program to perform GEMV as follows:
    // 16x WR_SBK to write each row of W from shared buffer to PIM banks: 
    //      TOP    LEFT 16x16 --> RO=0,CO=0, TOP    RIGHT 16x16 --> RO=0,CO=1, BOTTOM LEFT 16x16 --> RO=0,CO=2, BOTTOM RIGHT 16x16 --> RO=0,CO=3
    //      with Opsize=4, because inceremt is in CO and the way matrix W is stored in shared buffer allows for this
    // 1x  WR_GB to write vec_x from shared buffer to global buffer: 
    //      TOP 16x1 --> global buffer index 0, BOTTOM 16x1 --> global buffer index 1 (Opsize=2, because increment is in global buffer address and the way vector is stored in shared buffer allows for this: 0,1 in both shared buffer and global buffer)
    // 2x  WR_BIAS to write bias to accumulation registers in PIM PU
    //      Write bias for TOP HALF (first 16 elements) to accumulation register REGID=0 in PIM PU from shared buffer index 66 and bias for BOTTOM HALF (next 16 elements) to accumulation register REGID=1 in PIM PU from shared buffer index 67
    // 2x  MAC_ABK to perform the matrix-vector multiplication (GEMV) and write results to accumulation registers in PIM PU:
    //      Issue MAC_ABK with RO=0,CO=0,GB=0,OPsize=2 to process TOP LEFT (CO=0) and TOP RIGHT (CO=1) sub-matrices with TOP 16x1 and BOTTOM 16x1 global buffer vectors respectively and accumulate in REGID=0
    //      Issue MAC_ABK with RO=0,CO=2,GB=0,OPsize=2 to process BOTTOM LEFT (CO=2) and BOTTOM RIGHT (CO=3) sub-matrices with TOP 16x1 and BOTTOM 16x1 global buffer vectors respectively and accumulate in REGID=1
    // 2x  RD_MAC to read the results from accumulation registers (0, 1) in PIM PU to shared buffer index 68 and 69
    cent_instr_t program_instructions[23];
    u32 program_length = 23; // 16 WR_SBK + 1 WR_GB + 2 WR_BIAS + 2 MAC_ABK + 2 RD_MAC
    u32 program_start_index = 0; // start at the beginning of the instruction buffer

    // Build the 16 WR_SBK instructions to write from shared buffer to PIM banks for the matrix (TOP LEFT 16x16 --> RO=0,CO=0, TOP RIGHT 16x16 --> RO=0,CO=1, BOTTOM LEFT 16x16 --> RO=0,CO=2, BOTTOM RIGHT 16x16 --> RO=0,CO=3 with OPsize=4)
    for (int i = 0; i < 16; i++) {
        program_instructions[i] = build_wr_sbk(0, 4, i, 0, 0, 2 + (4 * i)); // rows start from index 2 in shared buffer, OPsize=4
    }

    // Build the 1 WR_GB instructions to write vec_x from shared buffer to global buffer: TOP 16x1 --> global buffer index 0, BOTTOM 16x1 --> global buffer index 1 ) OPsize=2
    program_instructions[16] = build_wr_gb(0, 2, 0, 0); // TOP 16x1 is at index 0 in shared buffer and BOTTOM 16x1 is at index 1 in shared buffer.

    // Build the 2 WR_BIAS instructions to write bias to accumulation registers in PIM PU
    program_instructions[17] = build_wr_bias(0, 66, 0); // bias for TOP HALF to accumulation register 0
    program_instructions[18] = build_wr_bias(0, 67, 1); // bias for BOTTOM HALF to accumulation register 1

    // Build the 2 MAC_ABK instructions to perform the matrix-vector multiplication (GEMV) and write results to accumulation registers in PIM PU:
    program_instructions[19] = build_mac_abk(0, 2, 0, 0, 0, MAC_OP_GEMV, 0); // Issue MAC_ABK with RO=0,CO=0,GB=0,OPsize=2 to process TOP LEFT (CO=0) and TOP RIGHT (CO=1) with TOP 16x1 and BOTTOM 16x1 global buffer vectors and accumulate in REGID=0
    program_instructions[20] = build_mac_abk(0, 2, 0, 2, 0, MAC_OP_GEMV, 1); // Issue MAC_ABK with RO=0,CO=2,GB=0,OPsize=2 to process BOTTOM LEFT (CO=2) and BOTTOM RIGHT (CO=3) with TOP 16x1 and BOTTOM 16x1 global buffer vectors and accumulate in REGID=1

    // Build the 2 RD_MAC instructions to read the results from accumulation registers (0, 1) in PIM PU to shared buffer index 68 and 69
    program_instructions[21] = build_rd_mac(0, 68, 0); // read results from accumulation register 0 to index 68 in shared buffer
    program_instructions[22] = build_rd_mac(0, 69, 1); // read results from accumulation register 1 to index 69 in shared buffer

    // Construct the program struct
    cent_program_t program = {
        .instructions = program_instructions,
        .length = program_length,
        .start_index = program_start_index
    };

    // Load the program into the instruction buffer
    xil_printf("Loading program into instruction buffer\r\n");
    cent_load_program(&program);

    // Write interface control registers
    xil_printf("Writing control registers to start execution\r\n");
    // Write 0x1 to ctrl register to enable
    cent_write_ctrl(0x1);
    // Write start index of the program to cmd_base register
    cent_write_cmd_base(program.start_index * sizeof(cent_instr_t));
    // Write length of the program to cmd_len register
    cent_write_cmd_len(program.length);
    // Fire the doorbell to start execution
    cent_fire_doorbell();

    // Poll the status register until no longer busy (busy is bit 1 in status register)
    xil_printf("Polling status register...\r\n");
    u32 status;
    do {
        status = cent_read_status();
    } while (status & 0x2);

    // Read performance register
    u32 perf = cent_read_perf();
    xil_printf("Performance in cycles: %u\r\n", perf);

    // Clear sticky bits
    cent_write_status(status);

    // Read the results from shared buffer index 68 and 69
    u16 result[32];
    cent_read_shared_buffer(68, &result[0]); // read first 16 results
    cent_read_shared_buffer(69, &result[16]); // read next 16 results

    // Print the results
    xil_printf("GEMV Result with No Activation in bf16 hex format:\r\n");
    print_vec(result, 32);

    // Verify results
    bool passed = true;
    for (int i = 0; i < 32; i++) {
        // Calculate ULPS error by converting expected and actual results to signed 16-bit integers and taking the absolute difference
        // This assumes that both result and expected_result are both positive or both negative (We assume that result and expected_result will not be that far off from each other such that one is positive and the other is negative)
        const s16 tol = 0; // No error allowed, should exactly match pytorch results
        s16 err = abs((s16)result[i] - (s16)expected_result_32x1_gemv[i]);
        xil_printf("result[%d] = 0x%04X, expected = 0x%04X, abs error = %u\r\n", i, result[i], expected_result_32x1_gemv[i], err);
        if (err > tol) {
            passed = false;
        }
    }
    if (passed) {
        xil_printf("32x32 GEMV with No Activation Test V1 Passed!!\r\n");
    } else {
        xil_printf("32x32 GEMV with No Activation Test V1 Failed!! See output above.\r\n");
    }

    return passed;
}

bool cent_test_gemv_128x128() {
    xil_printf("\r\n--- Running 128x128 GEMV with No Activation Test ---\r\n");

    // This test is similar to the previous GEMV 32x32 V1 but with a larger matrix and same no activation.
    // Most of the lengthy comments will not be included in this test but refer to cent_test_gemv_32x32 for more detailed explanations and mental model.

    xil_printf("Loading vector x and matrix W into shared buffer...\r\n");
    // vec x has 8 subvectors, write to shared buffer index 0 to 7
    for (int i = 0; i < 8; i++) {
        cent_write_shared_buffer(0 + i, &x_128x1[i*16]);
    }

    // Write W to shared buffer index 8 to 1031. 64 16x16 sub-matrices, each take 16 indices in shared buffer. 
    for (int r = 0; r < 16; r++) { // For each row in the sub-matrices (16 rows total)
        for (int h_tile = 0; h_tile < 8; h_tile++) { // For each horizontal tile (TOP, BOTTOM)
            for (int v_tile = 0; v_tile < 8; v_tile++) { // For each vertical tile (LEFT, RIGHT)
                int sbuf_idx = 8 + (64*r) + (8*h_tile) + v_tile;
                int w_row = r + (16*h_tile); // row in W
                int w_col = v_tile * 16; // column in W

                cent_write_shared_buffer(sbuf_idx, &W_128x128[w_row][w_col]);
            }
        }
    }

    // bias has 8 subvectors to shared buffer index 1032 to 1039
    for (int i = 0; i < 8; i++) {
        cent_write_shared_buffer(1032 + i, &bias_128x1[i*16]);
    }

    // Build program:
    // 16x WR_SBK with OPsize=64
    // 1x  WR_GB with OPsize=8
    // 8x  WR_BIAS to regids 0-7
    // 8x  MAC_ABK with OPsize=8
    // 8x  RD_MAC to shared buffer index 1040 to 1047 (final results)
    cent_instr_t program_instructions[41];
    u32 program_length = 41;
    u32 program_start_index = 0;

    for (int i = 0; i < 16; i++) {
        program_instructions[i] = build_wr_sbk(0, 64, i, 0, 0, 8 + (64 * i));
    }

    program_instructions[16] = build_wr_gb(0, 8, 0, 0);

    for (int i = 0; i < 8; i++) {
        program_instructions[17 + i] = build_wr_bias(0, 1032 + i, i);
    }

    for (int i = 0; i < 8; i++) {
        program_instructions[25 + i] = build_mac_abk(0, 8, 0, 8 * i, 0, MAC_OP_GEMV, i);
    }

    for (int i = 0; i < 8; i++) {
        program_instructions[33 + i] = build_rd_mac(0, 1040 + i, i);
    }

    cent_program_t program = {
        .instructions = program_instructions,
        .length = program_length,
        .start_index = program_start_index
    };

    xil_printf("Loading program into instruction buffer\r\n");
    cent_load_program(&program);

    xil_printf("Writing control registers to start execution\r\n");
    cent_write_ctrl(0x1);
    cent_write_cmd_base(program.start_index * sizeof(cent_instr_t));
    cent_write_cmd_len(program.length);
    cent_fire_doorbell();

    xil_printf("Polling status register...\r\n");
    u32 status;
    do {
        status = cent_read_status();
    } while (status & 0x2);

    if (status & 0x0C) {
        xil_printf("HARDWARE ERROR ABORT! Status: 0x%08X\r\n", status);
        cent_write_status(status);
        return false;
    }

    u32 perf = cent_read_perf();
    xil_printf("Performance in cycles: %u\r\n", perf);

    cent_write_status(status);

    u16 result[128];
    for (int i = 0; i < 8; i++) {
        cent_read_shared_buffer(1040 + i, &result[16 * i]);
    }

    xil_printf("GEMV Result with No Activation in bf16 hex format:\r\n");
    print_vec(result, 128);

    bool passed = true;
    for (int i = 0; i < 128; i++) {
        const s16 tol = 0; // No error allowed, should exactly match pytorch results
        s16 err = abs((s16)result[i] - (s16)expected_result_128x1_gemv[i]);
        xil_printf("result[%d] = 0x%04X, expected = 0x%04X, abs error = %u\r\n", i, result[i], expected_result_128x1_gemv[i], err);
        if (err > tol) {
            passed = false;
        }
    }
    if (passed) {
        xil_printf("128x128 GEMV with No Activation Test Passed!!\r\n");
    } else {
        xil_printf("128x128 GEMV with No Activation Test Failed!! See output above.\r\n");
    }

    return passed;
}

bool cent_test_gemv_16x16_relu_pnm_acc() {
    xil_printf("\r\n--- Running 16x16 GEMV with ReLU Activation and PNM Accumulation with ones vector i.e. +1 ---\r\n");

    // This test will be the same as cent_test_gemv_16x16 but an additional PNM accumulation instruction inserted after the MAC_ABK+AF+RD_MAC instructions.

    // Print the input matrix in hex {w11, w12, ..., w1n}, {w21, w22, ..., w2n}, ..., {wm1, wm2, ..., wmn} format
    xil_printf("matrix W:\r\n");
    print_mat(&W_16x16[0][0], 16, 16);

    // Print the input vector in hex {va1, va2, ..., va16} format
    xil_printf("Input vector x:\r\n");
    print_vec(x_16x1, 16);

    // Print the bias vector in hex {vb1, vb2, ..., vb16} format
    xil_printf("Bias vector b:\r\n");
    print_vec(bias_16x1, 16);

    xil_printf("Loading vector x and matrix W into shared buffer...\r\n");
    // Write vec_x to shared buffer index 0
    cent_write_shared_buffer(0, x_16x1);

    // Write mat_W to shared buffer index 1 to index 16 (one row per index)
    for (int r = 0; r < 16; r++) {
        cent_write_shared_buffer(1 + r, &W_16x16[r][0]);
    }

    // Write bias to shared buffer index 17
    cent_write_shared_buffer(17, bias_16x1);

    // Write the ones vector to shared buffer index 18 (for PNM accumulation with addition of 1)
    cent_write_shared_buffer(18, x_16x1_ones);

    // Build a program to perform GEMV as follows:
    // 16x WR_SBK to write each row of mat_W from shared buffer to PIM banks (one row per bank)
    // 1x  WR_GB to write vec_x from shared buffer to global buffer
    // 1x  WR_BIAS to write bias to accumulation register 0 in PIM PU (0x0 for no bias)
    // 1x  MAC_ABK to perform the matrix-vector multiplication (GEMV) and write results to accumulation register 0 in PIM PU
    // 1x  AF to perform ReLU activation on the results in accumulation register 0 in PIM PU and write back to accumulation register 0
    // 1x  RD_MAC to read the results from accumulation register 0 in PIM PU to shared buffer
    // 1x  PNM to perform accumulation on the results from shared buffer and write back to shared buffer
    cent_instr_t program_instructions[22];
    u32 program_length = 22; // 16 WR_SBK + 1 WR_GB + 1 WR_BIAS + 1 MAC_ABK + 1 AF + 1 RD_MAC + 1 PNM
    u32 program_start_index = 0; // start at the beginning of the instruction buffer

    // Build the 16 WR_SBK instructions to write each row of mat_W from shared buffer to PIM banks at index 0 (one row per bank)
    for (int i = 0; i < 16; i++) {
        program_instructions[i] = build_wr_sbk(0, 1, i, 0, 0, 1 + i); // rows start from index 1 in shared buffer
    }

    // Build the WR_GB instruction to write vec_x from shared buffer to global buffer
    program_instructions[16] = build_wr_gb(0, 1, 0, 0); // vec_x is at index 0 in shared buffer

    // Build the WR_BIAS instruction to write bias to accumulation register 0 in PIM PU (0x0 for no bias) from shared buffer index 17
    program_instructions[17] = build_wr_bias(0, 17, 0); // bias is at index 17 in shared buffer

    // Build the MAC_ABK instruction to perform the matrix-vector multiplication (GEMV) and write results to accumulation register 0 in PIM PU
    program_instructions[18] = build_mac_abk(0, 1, 0, 0, 0, MAC_OP_GEMV, 0); // process mat_W with vec_x and accumulate in REGID=0

    // Build the AF instruction to perform ReLU activation on the results in accumulation register 0 in PIM PU and write back to accumulation register 0
    program_instructions[19] = build_af(0, AFID_RELU, 0);

    // Build the RD_MAC instruction to read the results from accumulation register 0 in PIM PU to shared buffer index 19
    program_instructions[20] = build_rd_mac(0, 19, 0); // read results to index 19 in shared buffer

    // Build the PNM instruction to perform accumulation on the results from shared buffer index 18 and write back to shared buffer index 19
    program_instructions[21] = build_pnm(1, PNM_FUNCID_ACC, 18, 19); // perform accumulation on results at index 19 with ones vector at index 18 and write back to index 18 in shared buffer, replacing the ones vector

    // Construct the program struct
    cent_program_t program = {
        .instructions = program_instructions,
        .length = program_length,
        .start_index = program_start_index
    };

    // Load the program into the instruction buffer
    xil_printf("Loading program into instruction buffer\r\n");
    cent_load_program(&program);

    // Write interface control registers
    xil_printf("Writing control registers to start execution\r\n");
    // Write 0x3 to ctrl register to enable and enable irq
    cent_write_ctrl(0x3);
    // Write start index of the program to cmd_base register
    cent_write_cmd_base(program_start_index);
    // Write length of the program to cmd_len register
    cent_write_cmd_len(program_length);
    // Fire the doorbell to start execution
    cent_fire_doorbell();

    // Poll the status register until no longer busy (busy is bit 1 in status register)
    xil_printf("Polling status register...\r\n");
    u32 status;
    do {
        status = cent_read_status();
    } while (status & 0x2);

    // Check for error
    if (status & 0x0C) { // Check Bit 2 (Err 0) and Bit 3 (Err 1)
        xil_printf("HARDWARE ERROR ABORT! Status: 0x%08X\r\n", status);
        cent_write_status(status);
        return false;
    }

    // Read performance register
    u32 perf = cent_read_perf();
    xil_printf("Performance in cycles: %u\r\n", perf);

    // Clear sticky bits
    cent_write_status(status);

    // Read the results from shared buffer index 19 (before Accumulation) and index 18 (after Accumulation)
    u16 result[16];
    cent_read_shared_buffer(19, result);

    // Print the results
    xil_printf("GEMV Result with ReLU Activation in bf16 hex format (before PNM Accumulation +1):\r\n");
    print_vec(result, 16);

    // Read the results from shared buffer index 18 (after Accumulation)
    u16 result_acc[16];
    cent_read_shared_buffer(18, result_acc);

    // Print the results
    xil_printf("GEMV Result with ReLU Activation in bf16 hex format (after PNM Accumulation +1):\r\n");
    print_vec(result_acc, 16);

    // Verify results
    bool passed = true;
    for (int i = 0; i < 16; i++) {
        const s16 tol = 5; // Activation functions can introduce some error since they are implemented in a piecewise linear approximation in hardware.
        s16 err = abs((s16)result_acc[i] - (s16)expected_result_16x1_gemv_relu_pnm_acc[i]);
        xil_printf("result[%d] = 0x%04X, expected = 0x%04X, abs error = %u\r\n", i, result_acc[i], expected_result_16x1_gemv_relu_pnm_acc[i], err);
        if (err > tol) {
            passed = false;
        }
    }
    if (passed) {
        xil_printf("16x16 GEMV with ReLU Activation and PNM Accumulation Test Passed!!\r\n");
    } else {
        xil_printf("16x16 GEMV with ReLU Activation and PNM Accumulation Test Failed!! See output above.\r\n");
    }

    return passed;
}

bool cent_test_ew_mul_16x1() {
    xil_printf("\r\n--- Running Element-wise Multiplication 16x1 Test ---\r\n");

    // Print vector a in hex {va1, va2, ..., va16} format
    xil_printf("Input vector a:\r\n");
    print_vec(a_16x1, 16);

    // Print vector b in hex {vb1, vb2, ..., vb16} format
    xil_printf("Input vector b:\r\n");
    print_vec(b_16x1, 16);

    // Write vector a to shared buffer index 0
    cent_write_shared_buffer(0, a_16x1);

    // Write vector b to shared buffer index 1
    cent_write_shared_buffer(1, b_16x1);

    // Build a program to perform element-wise multiplication as follows:
    // 1x WR_SBK to write vector a from shared buffer to PIM bank 0 RO=0,CO=0
    // 1x WR_SBK to write vector b from shared buffer to PIM bank 1 RO=0,CO=0
    // 1x EW_MUL to perform element-wise multiplication of vectors in PIM banks 0 and 1 and write results to PIM bank 2 RO=0,CO=0
    // 1x RD_SBK to read the results from PIM bank 2 RO=0,CO=0 to shared buffer index 2
    cent_instr_t program_instructions[4];
    u32 program_length = 4; // 2 WR_SBK + 1 EW_MUL + 1 RD_SBK
    u32 program_start_index = 0; // start at the beginning of the instruction buffer

    // Build the WR_SBK instruction to write vector a from shared buffer index 0 to PIM bank 0 RO=0,CO=0
    program_instructions[0] = build_wr_sbk(0, 1, 0, 0, 0, 0); // vector a is at index 0 in shared buffer

    // Build the WR_SBK instruction to write vector b from shared buffer index 1 to PIM bank 1 RO=0,CO=0
    program_instructions[1] = build_wr_sbk(0, 1, 1, 0, 0, 1); // vector b is at index 1 in shared buffer

    // Build the EW_MUL instruction to perform element-wise multiplication of vectors in PIM banks 0 and 1 and write results to PIM bank 2 RO=0,CO=0
    program_instructions[2] = build_ew_mul(0, 1, 0, 0); // multiply banks in all bank groups including our target bk0*bk1->bk2

    // Build the RD_SBK instruction to read the results from PIM bank 2 RO=0,CO=0 to shared buffer index 2
    program_instructions[3] = build_rd_sbk(0, 1, 2, 0, 0, 2); // read results to index 2 in shared buffer

    // Construct the program struct
    cent_program_t program = {
        .instructions = program_instructions,
        .length = program_length,
        .start_index = program_start_index
    };

    // Load the program into the instruction buffer
    xil_printf("Loading program into instruction buffer\r\n");
    cent_load_program(&program);

    // Write interface control registers
    xil_printf("Writing control registers to start execution\r\n");
    // Write 0x1 to ctrl register to enable
    cent_write_ctrl(0x1);
    // Write start index of the program to cmd_base register
    cent_write_cmd_base(program.start_index * sizeof(cent_instr_t));
    // Write length of the program to cmd_len register
    cent_write_cmd_len(program.length);
    // Fire the doorbell to start execution
    cent_fire_doorbell();

    // Poll the status register until no longer busy (busy is bit 1 in status register)
    xil_printf("Polling status register...\r\n");
    u32 status;
    do {
        status = cent_read_status();
    } while (status & 0x2);

    // Check for error
    if (status & 0x0C) { // Check Bit 2 (Err 0) and Bit 3 (Err 1)
        xil_printf("HARDWARE ERROR ABORT! Status: 0x%08X\r\n", status);
        cent_write_status(status);
        return false;
    }

    // Read performance register
    u32 perf = cent_read_perf();
    xil_printf("Performance in cycles: %u\r\n", perf);

    // Clear sticky bits
    cent_write_status(status);

    // Read the results from shared buffer index 2
    u16 result[16];
    cent_read_shared_buffer(2, result);

    // Print the results
    xil_printf("Element-wise Multiplication Result in bf16 hex format:\r\n");
    print_vec(result, 16);

    // Verify results
    bool passed = true;
    for (int i = 0; i < 16; i++) {
        const s16 tol = 0; // No error allowed, should exactly match pytorch results
        s16 err = abs((s16)result[i] - (s16)expected_result_16x1_ewmul[i]);
        xil_printf("result[%d] = 0x%04X, expected = 0x%04X, abs error = %u\r\n", i, result[i], expected_result_16x1_ewmul[i], err);
        if (err > tol) {
            passed = false;
        }
    }
    if (passed) {
        xil_printf("Element-wise Multiplication 16x1 Test Passed!!\r\n");
    } else {
        xil_printf("Element-wise Multiplication 16x1 Test Failed!! See output above.\r\n");
    }

    return passed;
}